-- Tenancy: the BRAND_PREDICATE sentinel (below) is replaced with `brand_id = ?` by the serving seam.
CREATE OR REPLACE VIEW iceberg.brain_serving.mv_metric_aov_all AS
WITH base AS (
  SELECT
    brand_id,
    currency_code,
    channel,
    SUM(order_value_minor) AS gross_revenue_minor,
    COUNT(DISTINCT order_id) AS order_count
  FROM iceberg.brain_serving.semantic_order
  WHERE ${BRAND_PREDICATE}
  GROUP BY 1, 2, 3
)
SELECT
  brand_id,
  currency_code,
  channel,
  gross_revenue_minor,
  order_count,
  (CAST(gross_revenue_minor AS double) / NULLIF(order_count, 0)) AS aov
FROM base;
